import React, { useState } from "react";
import { NOME_APP, CSS } from "./utils/constants";
import { LS } from "./utils/helpers";

// 1. DEFINIMOS OS COMPONENTES PRIMEIRO (para o React já conhecê-los)
export function Home({ onLogin, onPedido, clientUser, orders, todayOrds, maintenanceMode, handleLogoClick, NOME_APP, calcPontos, cart, setScreen }) {
  return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <header style={{ background:"#fff",borderBottom:"2px solid #FFF0F8",padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center" }}>
        <span style={{ fontSize:22,fontWeight:900,color:"#E91E8C",cursor:"pointer" }} onClick={handleLogoClick}>{NOME_APP}</span>
        <div style={{ color:"#E91E8C" }} onClick={() => cart.length > 0 ? setScreen("pedido-cart") : null}>
          🛒 {cart.length}
        </div>
      </header>
      <div style={{ padding:"20px 18px" }}>
        <h2>{clientUser ? `Bem-vinda, ${clientUser.nome}` : "Bem-vinda!"}</h2>
        <button onClick={onPedido}>🎂 Fazer Pedido</button>
        <button onClick={onLogin}>👤 Entrar</button>
      </div>
    </div>
  );
}

// 2. AGORA A FUNÇÃO APP (O cérebro)
export default function App() {
  const [screen, setScreen] = useState("home");
  const [cart, setCart] = useState([]);
  const [orders, setOrders] = useState([]);
const [pedInfo, setPedInfo] = useState({ entrega:"", hora:"", obs:"", regiao:null, enderecoEntrega:"" });

  return (
    <div className="App">
       <style>{CSS}</style>

       {screen === "home" && (
         <Home 
           NOME_APP={NOME_APP}
           clientUser={null}
           orders={orders}
           todayOrds={[]}
           maintenanceMode={false}
           handleLogoClick={() => console.log("Logo clicado")}
           calcPontos={() => 0}
           cart={cart}
           setScreen={setScreen}
           onPedido={() => setScreen("pedido-info")}
           onLogin={() => setScreen("client-login")}
         />
       )}
    </div>
  );
}
export function PedidoInfo({ pedInfo, setPedInfo, onBack, onProximo }) {
  return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <Hdr title="📅 Dados do pedido" onBack={onBack} />
      <div style={{ padding:18, maxWidth:500, margin:"0 auto" }}>

        <Fld label="Data de entrega">
           <input 
             type="date" 
             value={pedInfo.entrega} 
             onChange={e => setPedInfo({...pedInfo, entrega: e.target.value})} 
             style={{width:"100%", padding:"10px", borderRadius:10, border:"1px solid #E5D0EE"}} 
           />
        </Fld>

        <Fld label="Observações">
           <input 
             value={pedInfo.obs} 
             onChange={e => setPedInfo({...pedInfo, obs: e.target.value})} 
             style={{width:"100%", padding:"10px", borderRadius:10, border:"1px solid #E5D0EE"}} 
           />
        </Fld>

        <Btn ch="Montar meu pedido →" onClick={onProximo} />
      </div>
    </div>
  );
}
